<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class=" modal-header ui-draggable-handle d-flex">
                        <h5 class="modal-title">{{ $t('Reply') }}: {{ showTicketNumber }}</h5>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                        <span class="user-guide">
                            <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button"
                                aria-expanded="false" aria-controls="collapseExample"> <em
                                    class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                            <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                    <div class="con" v-html="$t('UgAddTicketReply')"></div>
                                </div>
                            </div>
                        </span>
                    </div>

                    <div class="modal-body">
                        <div class="heading-border mb-2">
                            <h5 class="h5"><span>Reply</span><small class="float-right"><a href="javascript:;"
                                                id="showReply" v-if="isDisabledButton == false" v-on:click="btnShowReply" title="Add Reply">
                                                <i class="fa fa-paperclip pr-2"></i>{{ $t('Add') }} {{ $t('Reply')
                                                }}</a></small></h5>
                        </div>
                        <div class="row">
                            <div class="col-xl-8">
                                <!-- {{ FormSchema }} -->
                                <dynamic-form lang="en" ref="replyTicket" :buttons="buttons" :schema="FormSchema"
                                    v-on:InvalidSubmit="checkError"  v-if="ShowReplyData">
                                    <template v-slot:tgslot-Description="{ data }">
                                        <ckeditor :editor="editor" @ready="onReady" v-model="data.fieldInfo.value">
                                        </ckeditor>
                                        <span name="Description" class="invalid-feedback d-block">{{ data.error }}</span>
                                    </template>
                                    <template v-slot:tgslot-Subject="{ data }">
                                        <label>{{ data.fieldInfo.value }} {{ ticketSubject }}</label>
                                    </template>
                                    <template v-slot:tgslot-ReplyTo="{ data }">
                                        <label>{{ data.fieldInfo.value }}{{ ticketReplyTo }} </label>
                                    </template>
                                </dynamic-form>
                            </div>

                            <div class="col-xl-4 pl-xl-0 mt-md-2"  v-if="ShowReplyData">
                                <div class="border no-padding h-100 bg-light">
                                    <div class="theme-primary partition">
                                        <span class="p-name text-white">{{ $t('Related Article') }}</span>
                                    </div>
                                    <div class="info-list infolistheight">

                                        <div class="col-sm-12 col-md-12 float-left">
                                            <div class="row mt-0" style="display:flex">
                                                <div class="col-12 col-sm-8 float-left pr-1 pl-0">
                                                    <div class="form-group">
                                                        <input id="txtRelatedArticleList" v-model="articleText"
                                                            maxlength="50" class="form-control" type="text"
                                                            @keypress="SearchRelatedArticle"
                                                            :placeholder="$t('Search by KeyWords')" autocomplete="off">
                                                    </div>
                                                </div>
                                                <div class="col-12 col-sm-4 float-left pl-0">
                                                    <div class="search-btm-btn background-0 text-left" style="display:flex">
                                                        <a :title="$t('Search')" @click="EnterRelatedArticleText()"
                                                            id="ancRelatedArticleList" href="javascript:;"
                                                            class="btn btn-success mr-1 px-4"><i
                                                                class="fa fa-search"></i></a>
                                                        <a href="javascript:;" id="ancClearRelatedArticleList"
                                                            :title="$t('Clear')" @click="resetRelatedArticleText()"
                                                            class="btn btn-danger clearsearchtext px-4"><i
                                                                class="fa fa-refresh"></i></a>
                                                    </div>
                                                </div>

                                            </div>
                                        </div>
                                        <div class="clearfix" style="clear:both;"></div>

                                        <div class="search-related-articles" style="display:none;">
                                            <i class="fa fa-search"></i>
                                            <div class="clearfix"></div>
                                            <span>{{ $t('Lookforticketrelated') }}</span>
                                        </div>
                                        <div class="listing mb-2" id="divRelatedArticleList"
                                            style="max-height:530px;overflow-y:auto">
                                            <div class="listing articlesList p-2" v-for="item in ArticleList">
                                                <div class="listing articlesList p-2" v-for="res in item.ART">
                                                    <p class="mb-0">
                                                        <span class="blue-time w-100 d-block">{{ res.TICKET_ARTICLE_TITLE }}
                                                            <a class="text-right float-right ancsetartticle single-action"
                                                                @click="SetArticleOnDesc(res)"><i
                                                                    class="fa fa-plus-circle"></i></a></span><br />
                                                        <span class="txt" v-html="res.TICKET_ARTICLE_DESC"></span>
                                                    </p>
                                                </div>

                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                        </div>
                        <hr/>
                        <div class="clearfix"></div>
                    </div>
                  <div class="col-lg-12">
                    <div id="accordionreply" class="w-100 activity-tab position-relative">
                        <div class="position-absolute bottom_filter_button p-0 mt-0"  v-show="showExpandCollapse">
                            <a href="javascript:;" id="ancreplyExpandAllCollapseAll"
                                 @click="ancreplyExpandAllCollapseAll()" class="position-relative"
                                 style="z-index:999;" :title="$t('ExpandAllCollapseAll')"
                                 data-toggle-tooltip="tooltip">{{ $t('ExpandAllCollapseAll') }}
                            </a>
                        </div>
                        <div class="clearfix"></div>
                        <div class="card ctkTech show"  v-for="(groupItem, key, index) in groupByDate">
                                    <div class="card-header">
                                        <a :class="{ 'card-link collapsed': index > 0, 'card-link': index === 0 }" style="color:#000" data-toggle="collapse" :href="'#collapseOneThread' + index">
                                            <div class="conversation-date heading-border"><span>{{ $t(key) }}</span></div>
                                        </a>
                                    </div>
                                    <div>
                                        <div :id="'collapseOneThread' + index" :class="{ 'collapse': index > 0, 'collapse show': index === 0 }">
                                            <div class="card-body">
                                                <div class="conversation-main">
                                                    <template v-for="(item, index) in groupItem">
                                                        <div class="conversation-time">
                                                            <span>{{ formatTime(item.createdAt) }}</span>
                                                        </div>
                                                        <div class="conversation-box-con">
                                                            <div class="conversation-box">
                                                                <div class="name-circle light-yellow">
                                                                    <img :src="item.avtar ? 'https://cogniterblob.blob.core.windows.net/' + GetUserInfo.ContainerName + '/Upload/UserProfileImage/' + item.avtar : '/Content/images/DefaultImages/avatar-icon.jpg'"
                                                                     alt="Image" width="51" height="51" style="font-size:12px" loading="lazy" />
                                                                </div>
                                                                <div class="conversation-content addednote-ticket">
                                                                    <span>
                                                                        <span class="sender-department" v-html="item.comment"></span>
                                                                    </span>
                                                                </div>
                                                                <div class="conversation-content">
                                                                    <div class="col-12 p-0 notesdata">
                                                                        <h6 class="text-muted time p-0">
                                                                            <i> 
                                                                                <b>{{ item.createdBy }}</b>
                                                                                <span>, {{$t('PostedOn')}} :</span><span class="sender-department" style="color : #dc3545!important"> 
                                                                                    <span class="text-danger" :title="formattedCreatedAt(item.createdAt)">
                                                                                        {{ formattedCreatedAt(item.createdAt) }}
                                                                                    </span>
                                                                                </span> 
                                                                            </i>
                                                                        </h6>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </template>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataServices from "@/services/DataService";
//import ClassicEditor from '@ckeditor/ckeditor5-build-classic';

export default {
    // components: {
    //     "ckeditor": CKEditor.component
    // },
    props: {
        configdata: {
            type: Array,
            required: true
        },
        id: {
            type: Number,
            required: false
        },
        isDisabledButton:{
             type:Boolean,
             required:true
        },
        modulename: {
            type: String,
            required: true
        },
        showTicketNumber: {
            type: String,
            required: false
        },
        submodulecode: {
            type: String,
            required: true
        },
        callbackfunction: {
            type: Function
        },
        DraftTicketData: {
            type: Array,
            required: true
        },
    },
    data() {
        return {
            editor: this.CLASSIC_EDITOR,
            content: "<h1>Some initial content</h1>",
            ticketType: '',
            isLoading: false,
            TicketBindList: [],
            Description: null,
            ShowReplyData:false,
            Showtab: 1,
            FileName: null,
            file: null,
            ReplyTicketList: [],
            checkFileValidSize: false,
            checkFileValidExt: false,
            allowedPerFileSizeInMb: 0,
            disallowFileTypes: '',
            ArticleList: [],
            TicketThreadId: null,
            TicketThreadToId: 0,
            ticketThreadTo: 0,
            raisedByEmail: '',
            CreatedBy: 0,
            isSupportTicket: false,
            StatusCode: '',
            ticketSubject: '',
            threadDescription: '',
            articleText: '',
            ticketReplyTo: '',
            fileTypeList: [],
            ReplyCommentList: [],
            showExpandCollapse:false,
            ticketModel: {
                transferDescription: '',
                transferType: '',
                TicketId: 0,
                ModuleName: '',
                SubModuleCode: '',
                TicketThreadId: '',
                TicketThreadToId: 0,
                RepliedBy: 0,
                StatusCode: '',
                fileData: [],
                TicketThreadTo: 0,
                RaisedByEmail: '',
                isSupportTicket:false

            },
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('Subject'),
                            name: "Subject",
                            value: "",
                            placeholder: "",
                            // validationRules: { "required": true, max: 200 },
                        },
                        {
                            astype: "SlotField",
                            label: this.$t('Reply To'),
                            name: "ReplyTo",
                            value: "",
                            placeholder: "",
                            // validationRules: { "required": true, max: 200 },
                        },
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SelectField",
                            mode: "tag",
                            label: this.$t('Canned Reply'),
                            name: "CannedReply",
                            value: "",
                            config: {
                                options: [],
                                showAddIcon: false,
                                onChange: this.onChangeTemplate
                            },
                            placeholder: this.$t('Select Template'),
                            validationRules: { "required": false, max: 4000 },
                        }
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "FileField",
                            showLabel: false,
                            name: "ListAttachment",
                            value: "",
                            placeholder: "",
                            validationRules: "",
                            FieldIndex: 0,
                            config: {
                                maxSize: 5,
                                onChange: this.GetBase64String,
                                showAddIcon: false,
                                onAddButtonClick: "",
                                multiple: true
                            },
                        }
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",
                            placeholder: "",
                            config: {
                                options: [],

                            },
                            settings: {
                                isInSlot: true
                            },
                            visibility: true,
                            validationRules: { "required": true, max: 4000 },
                        },
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-warning save",
                    value: 'TICKET_REPLY_DRAFT',
                    text: "<i class='fa fa-save pr-2'></i>Save As Draft",
                    onClick: this.UploadFileWithReply
                },
                {
                    type: "submit",
                    class: "btn btn-success save",
                    value: 'ACT',
                    text: "<i class='fa fa-save pr-2'></i>Submit Reply",
                    onClick: this.UploadFileWithReply
                }
            ]
        }
    },
    computed: {
        groupByDate() {
            var vm = this;
            let groups = {};
            vm.ReplyCommentList.forEach(item => {
                let date = item.createdAt.substring(0, 10);
                if (groups[date]) {
                    groups[date].push(item);
                } else {
                    groups[date] = [item];
                }
            });

            return groups;
        }
    },
    created: async function () {
        //this.BindBillingTicketType();
        var vueObj = this;
        this.configData();
        if(vueObj.DraftTicketData && vueObj.DraftTicketData[0].threadDescription != null && vueObj.DraftTicketData[0].threadDescription != "")
        {
            vueObj.TicketThreadId = vueObj.DraftTicketData[0].thredid;
            vueObj.threadDescription = vueObj.DraftTicketData[0].threadDescription
        }
         await vueObj.GetReplyCommentList();
        setTimeout(function () {
            if(vueObj.ReplyCommentList.length > 0){
                vueObj.showExpandCollapse = true;
            }
            vueObj.FetchData();
        }, 400);
    },
    methods: {
        formattedCreatedAt(createdAt) {
            const dateObj = new Date(createdAt);
            const date = dateObj.toLocaleDateString();
            const time = dateObj.toLocaleTimeString('en-US', { 
                hour: '2-digit', 
                minute: '2-digit', 
                //second: '2-digit',
                hour12: true 
            });
            return `${date} ${time}`;
        },
        ancreplyExpandAllCollapseAll: async function () {
            var vm = this;
            if (vm.Showtab == 0) {
                vm.Showtab = 1;
                $("#accordionreply").find('.collapse').collapse('hide');
            } else {
                vm.Showtab = 0;
                $("#accordionreply").find('.collapse').collapse('show')
            }
          
        },
        btnShowReply: function () {
            var vueObj=this;
            var param = `controller=Ticketing&action=LoadReplyTab`;
            DataServices.CheckPrivilege(param).then(function (response) {
                if (response.data) {
                    if (vueObj.ShowReplyData == false) {
                        vueObj.ShowReplyData = true;
                    }
                    else {
                        vueObj.ShowReplyData = false;
                    }
                }else{
                    vueObj.ShowAlert(vueObj.$t("NotAuthorizedSection"), "warning", true, vueObj.$t("Alert"));  
                }
            })
            
        },
        toPrettyString(userDate) {
            //debugger;
            const now = new Date();
            const date = new Date(userDate);
            const ts = Math.abs(now - date); // Time difference in milliseconds
            const delta = ts / 1000; // Convert milliseconds to seconds

            if (delta < 60) {
                return 'few seconds ago';
            }
            if (delta < 120) {
                return 'a minute ago';
            }
            if (delta < 2700) { // 45 * 60
                return `${Math.floor(delta / 60)} minutes ago`;
            }
            if (delta < 5400) { // 90 * 60
                return 'an hour ago';
            }
            if (delta < 86400) { // 24 * 60 * 60
                return `${Math.floor(delta / 3600)} hours ago`;
            }
            if (delta < 172800) { // 48 * 60 * 60
                return 'yesterday';
            }
            if (delta < 2592000) { // 30 * 24 * 60 * 60
                return `${Math.floor(delta / 86400)} days ago`;
            }
            if (delta < 31104000) { // 12 * 30 * 24 * 60 * 60
                const months = Math.floor(delta / (30 * 86400));
                return months <= 1 ? '1 month ago' : `${months} months ago`;
            }
            const years = Math.floor(delta / (365 * 86400));
            return years <= 1 ? '1 year ago' : `${years} years ago`;
        },
        async GetReplyCommentList() {
            var vueObj = this;
            vueObj.isLoading = true;
            debugger;
            var url = `ticketId=${vueObj.id}`;
            await DataServices.GetReplyCommentList(url).then(response => {
                if (response.data.Status = "Success") {
                    if (response.data != "" && response.data != null) {
                        if (response.data.length > 0) {
                            vueObj.ReplyCommentList = response.data;
                           // vueObj.TotalRecords = response.data.Result.data[0].TOTALRECORDS;
                            vueObj.isLoading = false;
                        } else {
                            //vueObj.TotalRecords = 0
                            vueObj.ReplyCommentList = [];
                            vueObj.isLoading = false;
                        }
                    } else {
                        //vueObj.TotalRecords = 0
                        vueObj.ReplyCommentList = [];
                        vueObj.isLoading = false;
                    }
                }
            })
        },
        SearchRelatedArticle: function (eDescriptionvent) {
            ////debugger;
            var search = event.key;
            var vm = this;
            vm.ShowRelatedArticleList(search);

        },
        SizeToMb: function (bytes) {
            // ////debugger;
            var vueObj = this;
            var sizeInBuytes = parseInt(vueObj.allowedPerFileSizeInMb, 10) * 1048576;
            if (bytes > sizeInBuytes) {
                return -1;
            }
            else {
                var byesInMB = (bytes / 1024) / 1024;
                return byesInMB;
            }
        },
        configData: function (value) {
            // ////debugger;
            var vm = this;
            var data = vm.configdata;
            $.each(data, $.proxy(function (index1, item) {
                if (item.CORE_CONFIG_KEY == "TicketFileSize") {
                    this.allowedPerFileSizeInMb = item.CONFIG_DATA_VALUE;
                }
                else if (item.CORE_CONFIG_KEY == "TicketDisallowedFileTypes") {
                    this.disallowFileTypes = item.CONFIG_DATA_VALUE;
                    this.fileTypeList = this.AttachmentDisallowedFileType(this.disallowFileTypes);
                    vm.FormSchema[2].Data[0].config.reject = this.fileTypeList;
                }
            }, this));

        },
        EnterRelatedArticleText: function () {
            var vm = this;
            var search = vm.articleText;
            vm.ShowRelatedArticleList(search);
        },
        resetRelatedArticleText: function () {
            var vm = this;
            vm.articleText = '';
            vm.FormSchema[3].Data[0].value = '';
            vm.ArticleList = [];
        },
        SetArticleOnDesc: function (res) {
            var vm = this;
            vm.FormSchema[3].Data[0].value = '';
            vm.FormSchema[3].Data[0].value = res.TICKET_ARTICLE_TITLE + '<br>' + res.TICKET_ARTICLE_DESC;
        },
        checkError: function (e, x) {
        },
        onReady(editor) {
            editor.ui.getEditableElement().parentElement.insertBefore(
                editor.ui.view.toolbar.element,
                editor.ui.getEditableElement()
            );
        },
        setFile: function (e) {
            var vm = this;
            vm.file = e.target.files[0];
            vm.FileName = e.target.files[0].name;
        },
        onChangeTemplate: async function (e, y, z) {
            var vm = this;
            // vm.Description = e.target.value;
            var cannedReply = [];
            cannedReply = y.config.options;
            cannedReply.forEach((item) => {
                if (item.value == e.target.value) {
                    vm.FormSchema[3].Data[0].value = item.value;
                }
            });
        },
        ShowRelatedArticleList: async function (search) {
            var vm = this;
            var url = `search=${search}`;
            await DataServices.RelatedArticleList(url).then(function (response) {
                if (response.data != null) {
                    vm.ArticleList = response.data.result.data;
                }

            })
        },
        FetchData: async function () {
            var vm = this;
            var url = `ticketId=${vm.id}`;
            await DataServices.AssignTransferTicket(url).then(function (response) {
                if (response.data != null) {
                    vm.ReplyTicketList = response.data.data;
                    vm.TicketThreadToId = vm.ReplyTicketList.ticketThreadToId == 0 ?  vm.ReplyTicketList.ticketThreadToId : vm.ReplyTicketList.createdBy;
                    vm.CreatedBy = vm.ReplyTicketList.ticketThreadToId;
                    vm.StatusCode = vm.ReplyTicketList.ticketStatus;
                    vm.ticketSubject = vm.ReplyTicketList.ticketSubject;
                    vm.ticketReplyTo = vm.ReplyTicketList.ticketThreadTo;
                    vm.raisedByEmail =  vm.ReplyTicketList.raisedByEmail;
                    vm.ticketThreadTo =  vm.ReplyTicketList.ticketThreadTo;
                    vm.isSupportTicket = vm.ReplyTicketList.isSupportTicket;
                    if(vm.threadDescription != null)
                    {
                        vm.FormSchema[3].Data[0].value = vm.threadDescription;
                    }
                    if (vm.ReplyTicketList.replyTemplate != null) {
                        vm.ReplyTicketList.replyTemplate.forEach((item, index) => {
                            (vm.FormSchema)[1].Data[0].config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                        // vm.$refs.replyTicket.UpdateKeyValue();
                    }
                }
            })
        },
        GetBase64String: function (evt, field) {
            try {                
                var vm = this;
                vm.fileData = [];
                var fl = evt.target.files || field.value; 
                var f = fl[0];
                var reader = new FileReader();
                reader.onload = (function (theFile) {
                    return function (e) {
                        var binaryData = e.target.result;
                        var base64StringEncoded = window.btoa(binaryData);
                        var fileName = f.name;
                        vm.fileName = fileName;
                        var n = fileName.lastIndexOf(".");
                        var extensionName = fileName.substring(n + 1, fileName.length);
                        vm.fileExt += "." + extensionName;
                        var attachemnetMime = '{"ContentType":"' + f.type + '","Size":"' + f.size + '","Extension":"' + extensionName + '"}';
                        var fileSize = f.size;
                        vm.fileSize = fileSize;
                        var fileObj = {
                            attachement_mime: attachemnetMime,
                            fileName: fileName,
                            base64String: base64StringEncoded,
                            fileSize: f.size,
                            contentType: f.type
                        };
                        vm.fileData.push(fileObj);
                    };
                })(f);
                reader.readAsBinaryString(f);
            }
            catch (ex) {
            }
        },
        UploadFileWithReply: function (btnType) {           
            var vm = this; 
            if (vm.FormSchema[3].Data[0].value == '' || vm.FormSchema[0].Data[0].value == null) {
                this.showError = true;
            }
            else {

                var extArray = vm.disallowFileTypes.split(',');
                if (extArray.includes(vm.fileExt)) {
                    vm.checkFileValidExt = false;
                    vm.ShowAlert(vm.$t("InvalidFileUploadMsg", vm.fileName, vm.disallowFileTypes), "warning", true, vm.$t("Alert"));
                }
                else {
                    vm.checkFileValidExt = true;
                }

                var fileSizeInMB = this.SizeToMb(vm.fileSize);

                if (fileSizeInMB > parseInt(vm.allowedPerFileSizeInMb, 10)) {
                    vm.checkFileValidSize = false;
                    vm.ShowAlert(vm.$t("ExceedAllowedSize", vm.fileName, vm.allowedPerFileSizeInMb), "warning", true, vm.$t("Alert"));
                }
                else {
                    vm.checkFileValidSize = true;
                }

                if (fileSizeInMB < 0) {
                    vm.checkFileValidSize = false;
                    vm.ShowAlert(vm.$t("ExceedAllowedSize", vm.fileName, vm.allowedPerFileSizeInMb), "warning", true, vm.$t("Alert"));

                } else {
                    vm.checkFileValidSize = true;
                }

                if (vm.checkFileValidExt == true && vm.checkFileValidSize == true) {

                    if(btnType.class == 'btn btn-success save')
                    {
                        vm.buttons[1].class = 'btn btn-success save disabled';
                    }
                    if(btnType.class == 'btn btn-warning save')
                    {
                        vm.buttons[0].class = 'btn btn-warning save disabled'; 
                    }  
                    vm.ticketModel.TicketId = vm.id == 0 || vm.id == null ? vm.TicketNoteId : vm.id;
                    vm.ticketModel.ModuleName = vm.modulename;
                    vm.ticketModel.SubModuleCode = vm.submodulecode;
                    vm.ticketModel.fileData = vm.fileData;
                    vm.ticketModel.RaisedByEmail = vm.raisedByEmail;
                    vm.ticketModel.TicketThreadTo = vm.ticketThreadTo;
                    vm.ticketModel.TicketThreadId = vm.TicketThreadId != null ? vm.TicketThreadId : 0;
                    vm.ticketModel.TicketThreadToId = vm.CreatedBy;
                    vm.ticketModel.isSupportTicket = vm.isSupportTicket;
                    vm.ticketModel.transferDescription = vm.FormSchema[3].Data[0].value;
                    vm.ticketModel.StatusCode = btnType.value == 'TICKET_REPLY_DRAFT' ? 'TICKET_REPLY_DRAFT' : 'ACT';
                    var formData = JSON.stringify(vm.ticketModel);
                    DataServices.TicketReply(formData).then((response) => {
                        try {
                            if (response.data != null && response.data != "" && response.data.status == "Success") {                              
                                vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Reply")]), "success", true, vm.$t("Alert"));
                                $("input[type=text]").val('');
                                //vueObj.$validator.reset();
                                vm.Close();
                                vm.callbackfunction();                               
                            }
                            else {
                                // ShowAlert(Globalize.localize('InvalidFileTypMsg'), "failure", true, Globalize.localize("Alert"));
                                vm.FileSrc = '';
                                vm.Close();
                                $("input[type=text]").val('');

                            }
                        } catch (exinner) {
                            return HandleErrorOccured(exinner, 'saveNote');
                        }                        
                    });
                }


            }

        },
        Close: function () {            
             var vueObj = this;
            // this.Description = null; 
            // this.FileName = null;   
            // this.file = null;  
            // this.FormSchema[2].Data[0].config.onChange = this.GetBase64String;
            vueObj.threadDescription = null;
            vueObj.TicketThreadId = 0;
            this.$parent.showReplyTicketModal = false;
            //this.$parent.LoadNotesForQuickView();
        },
    }
}
</script>